var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"에블린, 갑자기 이게 무슨 난리야?","JPN":"エヴリン、急に何の騒ぎだ？","ENG":"What's going on, Evelyn?","TWN":"伊芙琳，這到底是怎麼了？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"모르겠어. 별다른 전조 없이 갑자기 침식체가 나타났거든.","JPN":"わからない。これといった前触れもなく、急に侵食体が現れたわ。","ENG":"I have no idea. These C.O.s appeared out of nowhere without any prior indication.","TWN":"我也不知道。沒有任何徵兆，突然就出現了侵蝕體。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭔가 낌새가 안 좋은데......","JPN":"何か異常な気配だな……","ENG":"Something doesn't feel right...","TWN":"感覺不太對勁啊……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"우리가 여기 자리잡은 뒤로 침식체가 출몰했던 적은 없잖아.","JPN":"妾たちがここに居着いてから侵食体が出没したことはなかったよな？","ENG":"We've never had C.O.s appear since we settled down here.","TWN":"我們來到這裡後，可從來沒有出現過侵蝕體。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러게나 말이야.","JPN":"そうね。","ENG":"Tell me about it.","TWN":"是啊。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아, 혹시 이면세계에서 돌아올 때 지하실 문 닫는 걸 깜빡한 거 아냐?","JPN":"あ、ひょっとして裏世界から帰ってくる時に地下室の戸締りをうっかりしてたんじゃない？","ENG":"Oh, did we maybe forget to close the basement door when we got back from the Counterside?","TWN":"啊，難道從異界回來的時候忘了關好地下室的門？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흥. 베아트릭스의 이름을 물려 받은 내가 그런 바보 같은 짓을 할 리가 있겠어?","JPN":"なんだと。ベアトリクスの名を受け継いだ妾が、そんなバカな真似をするわけがない。","ENG":"Come on, I'm a Beatrix. You think I'd really make an amateur mistake like that?","TWN":"哼，我蘿拉怎麼可能會做那種蠢事。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 역시...... 할머니 때문인가 보네.","JPN":"それじゃ、やっぱり……お婆ちゃんの……","ENG":"In that case... It must be Granny May.","TWN":"那麼……是因為奶奶吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래. 메이 할머니가 죽으면서 발푸르기스 성을 봉인한 결계도 약해졌을 거야.","JPN":"そうだ。メイ婆さんが封印したヴァルプルギス城の結界が弱くなってきたかもしれない。","ENG":"Yes. The seal on Walpurgis Castle must have grown weak when Granny May passed away.","TWN":"對，梅伊奶奶去世後，魔女之夜城的封印結界應該是變弱了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"원래라면 눈에 보이지 않게 숨겨져 있었어야 할 성이 바보 견습들에게 보였던 것도......","JPN":"本来なら目に見えないように隠しておいたはずの城がバカ見習いどもに見えたのも……","ENG":"Because of that, those clumsy apprentices found the castle, which should have been hidden from their sight...","TWN":"這魔女之夜城原本應該是隱藏的，但是連傻瓜見習生都看得到了……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"갇혀 있던 인형들이 우리가 아는 것보다 이른 시기에 나타난 것도 그 때문이겠지.","JPN":"閉じ込めていた人形たちが予想以上に早い時期に現れたのも、そのせいだろう。","ENG":"and the puppets inside the castle became active sooner than we expected.","TWN":"而且被關的木偶出現的時間比我們預想的早，應該都是因為那個原因。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이번 할로윈 축제가 끝나면 한 번 대대적으로 손을 봐야겠어.","JPN":"今年のハロウィンが終わったら、大々的に補修しないと。","ENG":"We'd better patch it up big time once the Halloween festival is over.","TWN":"這次萬聖節慶典結束後，好好整修一番吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......그래. 우리 힘으로 가능하다면 말이야.","JPN":"……そうよね。私たちの力でできるならの話だけど。","ENG":"Yes... If it's something we can fix, that is.","TWN":"……嗯，如果我們的能力可以做到的話。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};